function solve(n) {
  function toBase36(num) {
    let digits = [];
    while (num > 0) {
      let remainder = num % 36;
      digits.push(remainder);
      num = Math.floor(num / 36);
    }
    digits = digits.reverse();
    return digits.map(digit => {
      if (digit < 10) return digit.toString();
      else return String.fromCharCode(65 + digit - 10);
    }).join('');
  }

  const n2 = n * n;
  const hexStr = n2.toString(16).toUpperCase();

  const n3 = n * n * n;
  const base36Str = toBase36(n3);

  return hexStr + base36Str;
}

